#!/bin/bash
# ─────────────────────────────────────────────────────────────────────────────
# ZLAR Gate Wrapper — Claude Code adapter
#
# Installed to ~/.claude/zlar-gate.sh by adapters/claude-code/install.sh.
# Do not edit this file directly — edit the source in adapters/claude-code/
# and re-run install.sh to regenerate.
#
# ZLAR_PROJECT_DIR is set at install time to the absolute path of the
# ZLAR repo on this machine. This is the only machine-specific line.
# ─────────────────────────────────────────────────────────────────────────────

ZLAR_PROJECT_DIR="__ZLAR_PROJECT_DIR__"
REAL_HOOK="${ZLAR_PROJECT_DIR}/bin/zlar-gate"

# Sanity check — fail closed if the gate binary is missing.
if [ ! -x "${REAL_HOOK}" ]; then
    printf '{"hookSpecificOutput":{"hookEventName":"PreToolUse","permissionDecision":"deny","permissionDecisionReason":"[gate:missing] ZLAR gate not found at %s — run adapters/claude-code/install.sh to repair"}}\n' "${REAL_HOOK}"
    exit 0
fi

# ── Parse .env (DO NOT source — sourcing is a code execution vector) ──
# Only extract known key=value pairs. Ignore everything else.
_parse_env() {
    local env_file="${ZLAR_PROJECT_DIR}/.env"
    if [ -f "${env_file}" ]; then
        while IFS='=' read -r key value; do
            [[ "${key}" =~ ^[[:space:]]*# ]] && continue
            [[ -z "${key}" ]] && continue
            value="${value%\"}"
            value="${value#\"}"
            value="${value%\'}"
            value="${value#\'}"
            case "${key}" in
                TELEGRAM_BOT_TOKEN|ZLAR_TELEGRAM_TOKEN)
                    export "${key}=${value}"
                    ;;
            esac
        done < "${env_file}"
    fi
}
_parse_env

# ── Startup notification (once per session, time-based dedup) ──
ACTIVE_FLAG="${ZLAR_PROJECT_DIR}/var/log/.gate-active"
STALE_SECONDS=120

if [ ! -f "${ACTIVE_FLAG}" ]; then
    SHOULD_ANNOUNCE=true
else
    LAST_MOD=$(stat -f %m "${ACTIVE_FLAG}" 2>/dev/null || stat -c %Y "${ACTIVE_FLAG}" 2>/dev/null || echo 0)
    NOW_EPOCH=$(date +%s)
    AGE=$(( NOW_EPOCH - LAST_MOD ))
    if [ "${AGE}" -gt "${STALE_SECONDS}" ]; then
        SHOULD_ANNOUNCE=true
    else
        SHOULD_ANNOUNCE=false
    fi
fi

if [ "${SHOULD_ANNOUNCE}" = "true" ]; then
    NOW=$(date -u +%Y-%m-%dT%H:%M:%SZ)
    echo "${NOW}" > "${ACTIVE_FLAG}" 2>/dev/null
    # macOS notification — fire and forget, ignored on Linux
    osascript -e 'display notification "ZLAR gate active" with title "ZLAR"' >/dev/null 2>&1 &
fi

exec "${REAL_HOOK}"
